import React, {useEffect, useState} from "react";
import {useCookies} from "react-cookie";
import PlayerDisplay from "./components/PlayerDisplay";
import styled from "styled-components";
import {Player, assignRoleToPlayers} from "./types/Player";
import GlobalStyle from "./GlobalStyle";
import RoleDisplay from "./components/RoleDisplay";
import AddPlayer from "./components/AddPlayer";


const App = () => {
    const [cookies] = useCookies();
    const [players, setPlayers] = useState<Player[]>();
    const [displayPlayers, setDisplayPlayers] = useState<Player[]>();
    const [roleToDisplay, setRoleToDisplay] = useState<never | string>();
    const [displayAddComponent, setDisplayAddComponent] = useState(false);
    useEffect(() => {
        // const plays=["سید حسین","سید علی موسوی","سید علی میری","سید محمد","سید مجتبی","دایی","آقا محسن","آقا محمد","آقا مهدی","امیررضا","امیرحسین"];
        // setCookie("players",plays);
        const playersName = cookies["players"] as string[];
        if (playersName === undefined) return;
        const players = assignRoleToPlayers(playersName);
        console.log(players);
        setPlayers(players);
        setDisplayPlayers(players);
    }, [displayAddComponent]);

    const onPlayerClicked = (playerName: string) => {
        const playerRole = displayPlayers!.find(player => player.name == playerName)!.role;
        setRoleToDisplay(playerRole);
        const players = displayPlayers!.filter(player => player.name != playerName) as Player[];
        setDisplayPlayers([...players]);
    };

    const closeRoleDisplay = () => {
        setRoleToDisplay("");
    };
    const onAddPlayerClicked=()=>setDisplayAddComponent(true);
    const onAddPlayerClose=()=>setDisplayAddComponent(false);
    return (
        <Container>
            <PlayersList>
                {
                    displayPlayers ?
                        displayPlayers?.map((player, index) =>
                            <PlayerDisplay key={index}
                                           playerName={player.name}
                                           playerClicked={onPlayerClicked}/>)
                        : <EmptyPlayers>بازیکنی ثبت نشده</EmptyPlayers>
                }
            </PlayersList>
            {roleToDisplay && <RoleDisplay role={roleToDisplay} closeComponent={closeRoleDisplay}/>}
            {displayAddComponent && <AddPlayer close={onAddPlayerClose}/>}
            <Menu>
                <MenuButton>{"حذف"}</MenuButton>
                <MenuButton onClick={onAddPlayerClicked}>{"افزودن"}</MenuButton>
            </Menu>
            <GlobalStyle/>
        </Container>
    );
};

const Container = styled.div`
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  width: 100vw;
  height: 100vh;
  background-color: #111;
`;

const PlayersList = styled.div`
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  align-items: center;
  width: 100vw;
  height: 90vh;
`;

const EmptyPlayers = styled.p`
  color: #fff;
  font-size: 3rem;
`;

const Menu = styled.div`
  display: flex;
  justify-content: space-evenly;
  align-items: center;
  width: 100vw;
  height: 10vh;
  background-color: #242424;
`;

const MenuButton = styled.button`
  font-size: 1.5rem;
  color: #fff;
  padding: .5rem 1rem;
  border-radius: .5rem;
  background-color: #555;
`;
export default App;