export type Player = {
    name: string,
    role: string
}

export const assignRoleToPlayers = (playersName: string[]): Player[] => {
    const playersCount = playersName.length;
    const countOfMainRoles = playerRoles.length;
    const countOfSparedRoles = playersCount - countOfMainRoles;
    let rolesToAssign: string[];
    if (countOfSparedRoles > 0) {
        const spearedRoles = new Array(countOfSparedRoles).fill(sparedRole);
        rolesToAssign = [...playerRoles, ...spearedRoles];
    } else {
        rolesToAssign = [...playerRoles];
    }
    const randomizeRolesToAssign = shuffle(rolesToAssign);
    return playersName.map<Player>((playerName, index) => {
        return {name: playerName, role: randomizeRolesToAssign[index]};
    });
};

const playerRoles = ["رییس مافیا",
    "مذاکره کننده",
    "مافیا ساده",
    "کاراگاه",
    "پزشک",
    "تک تیرانداز",
    "زره پوش",
    "شهروند ساده"];
const sparedRole = "شهروند ساده";

function shuffle(list: any[]) {
    for (let i = list.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [list[i], list[j]] = [list[j], list[i]];
    }
    return list;
}