import {createGlobalStyle} from "styled-components";

const GlobalStyle = createGlobalStyle`
  body {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
    font-size: 10px;
  }

  button {
    outline: none;
    border: none;
    background-color: transparent;
  }
`;

export default GlobalStyle;