import React, {useState} from "react";
import styled from "styled-components";
import {useCookies} from "react-cookie";

interface Props {
    close: () => void
}

const AddPlayer = ({close}: Props) => {
    const [inputValue, setInputValue] = useState("");
    const [cookies, setCookie] = useCookies();
    const nextButtonClicked = () => {
        let playersCookie = cookies["players"];
        let playersName = playersCookie ? playersCookie as string[] : [];
        playersName = [...playersName, inputValue];
        setCookie("players", playersName);
    };
    return (
        <Component>
            <Input type="text" onChange={e => setInputValue(e.target.value)}/>
            <NextButton onClick={nextButtonClicked}>بعدی</NextButton>
            <DoneButton onClick={close}>پایان</DoneButton>
        </Component>
    );
};


const Component = styled.div`
  position: fixed;
  top: 0;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  width: 100vw;
  height: 100vh;
  background-color: #000000;
  z-index: 1;
`;

const Input = styled.input`
  font-size: 2rem;
  color: white;
  width: 80%;
  background-color: #333;
`;

const NextButton = styled.button`
  font-size: 2rem;
  color: white;
  margin: 2rem;
  padding: .3rem 1rem;
  background-color: #333;
`;

const DoneButton = styled.button`
  font-size: 2rem;
  color: red;
  padding: .3rem 1rem;
  background-color: transparent;
`;
export default AddPlayer;