import React from "react";
import styled from "styled-components";

interface Props {
    role: string,
    closeComponent: () => void
}


const RoleDisplay = ({role, closeComponent}: Props) => {
    return (
        <Component>
            <Role>{role}</Role>
            <DoneButton onClick={closeComponent}>{"متوجه شدم"}</DoneButton>
        </Component>
    );
};

const Component = styled.div`
  position: fixed;
  top: 0;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  width: 100vw;
  height: 100vh;
  background-color: #000000cc;
  z-index: 1;
`;

const Role = styled.p`
  color: #fff;
  font-size: 3rem;
  padding: 3rem;
  border-radius: 2rem;
  background-color: #282828;
`;

const DoneButton = styled.button`
  color: #fff;
  font-size: 1.5rem;
  border-radius: 1rem;
  padding: .4rem 1rem;
  background-color: #1e90ffff;
`;

export default RoleDisplay;