import React from "react";
import styled from "styled-components";

interface Props {
    playerName: string,
    playerClicked: (name: string) => void
}

const PlayerDisplay = ({playerName, playerClicked}: Props) => {
    const onPlayerClicked = () => playerClicked(playerName);

    return (
        <PlayerComponent onClick={onPlayerClicked}>
            {playerName}
        </PlayerComponent>
    );
};
const PlayerComponent = styled.button`
  font-size: 1.5rem;
  margin: .6rem;
  padding: .5rem 1rem;
  border-radius: 1rem;
  color: #fff;
  background-color: #333;
`;
export default PlayerDisplay;